import React, { useState, useRef, useEffect } from 'react';
import { GoogleGenAI } from "@google/genai";
import { User } from '../../types';

interface Message {
    role: 'user' | 'model';
    text: string;
}

interface ChatAssistantProps {
    currentUser: User | null;
}

const ChatAssistant: React.FC<ChatAssistantProps> = ({ currentUser }) => {
    const [isOpen, setIsOpen] = useState(false);
    const [input, setInput] = useState('');
    const [messages, setMessages] = useState<Message[]>([
        { role: 'model', text: `Hello ${currentUser?.name || 'there'}! I'm SafetyBot. Need help with vehicle standards or inspection protocols?` }
    ]);
    const [isTyping, setIsTyping] = useState(false);
    const messagesEndRef = useRef<HTMLDivElement>(null);

    const scrollToBottom = () => {
        messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
    };

    useEffect(() => {
        if (isOpen) scrollToBottom();
    }, [messages, isOpen]);

    const handleSendMessage = async (e: React.FormEvent) => {
        e.preventDefault();
        if (!input.trim() || isTyping) return;

        const userMsg = input.trim();
        setInput('');
        setMessages(prev => [...prev, { role: 'user', text: userMsg }]);
        setIsTyping(true);

        try {
            const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
            const chat = ai.chats.create({
                model: 'gemini-3-flash-preview',
                config: {
                    systemInstruction: `You are SafetyCheck Pro AI (SafetyBot), an expert technical assistant for truck and trailer inspections. 
                    You assist inspectors and fleet managers. 
                    Your tone: Professional, precise, safety-first. 
                    Provide concise advice on vehicle safety, mechanical standards, and maintenance best practices. 
                    The current user is ${currentUser?.name || 'an inspector'} (${currentUser?.role || 'user'}).`,
                },
            });

            const response = await chat.sendMessage({ message: userMsg });
            const aiText = response.text || "I apologize, I'm having trouble processing that query right now.";

            setMessages(prev => [...prev, { role: 'model', text: aiText }]);
        } catch (error) {
            setMessages(prev => [...prev, { role: 'model', text: "Service connection interrupted. Please ensure you are online." }]);
        } finally {
            setIsTyping(false);
        }
    };

    return (
        <div className="fixed bottom-6 right-6 z-[110] no-print flex flex-col items-end">
            {/* Chat Window */}
            {isOpen && (
                <div className="mb-4 w-[340px] sm:w-[400px] h-[500px] bg-white rounded-[2rem] shadow-[0_20px_60px_-15px_rgba(0,0,0,0.3)] border border-slate-200 flex flex-col overflow-hidden animate-fadeIn origin-bottom-right">
                    {/* Header */}
                    <div className="bg-slate-900 p-5 flex justify-between items-center shrink-0">
                        <div className="flex items-center gap-3">
                            <div className="relative">
                                <div className="w-10 h-10 bg-gradient-to-tr from-indigo-600 to-indigo-400 rounded-xl flex items-center justify-center text-white shadow-lg">
                                    <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M9.75 17L9 20l-1 1h8l-1-1-.75-3M3 13h18M5 17h14a2 2 0 002-2V5a2 2 0 00-2-2H5a2 2 0 00-2 2v10a2 2 0 002 2z" /></svg>
                                </div>
                                <span className="absolute -bottom-1 -right-1 w-3.5 h-3.5 bg-emerald-500 border-2 border-slate-900 rounded-full"></span>
                            </div>
                            <div>
                                <h3 className="text-xs font-black text-white uppercase tracking-widest">SafetyBot AI</h3>
                                <p className="text-[9px] text-indigo-300 font-bold uppercase tracking-widest">Compliance Expert</p>
                            </div>
                        </div>
                        <button onClick={() => setIsOpen(false)} className="p-2 text-slate-400 hover:text-white transition-colors hover:bg-white/10 rounded-lg">
                            <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M6 18L18 6M6 6l12 12" /></svg>
                        </button>
                    </div>

                    {/* Messages Area */}
                    <div className="flex-1 overflow-y-auto p-5 space-y-4 bg-slate-50/50 scrollbar-hide">
                        {messages.map((msg, idx) => (
                            <div key={idx} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
                                <div className={`max-w-[85%] p-4 text-xs leading-relaxed shadow-sm ${
                                    msg.role === 'user' 
                                    ? 'bg-slate-900 text-white rounded-3xl rounded-tr-none' 
                                    : 'bg-white text-slate-700 border border-slate-200 rounded-3xl rounded-tl-none'
                                }`}>
                                    {msg.text}
                                </div>
                            </div>
                        ))}
                        {isTyping && (
                            <div className="flex justify-start">
                                <div className="bg-white border border-slate-200 p-4 rounded-3xl rounded-tl-none shadow-sm">
                                    <div className="flex gap-1.5">
                                        <div className="w-1.5 h-1.5 bg-indigo-400 rounded-full animate-bounce [animation-delay:-0.3s]"></div>
                                        <div className="w-1.5 h-1.5 bg-indigo-400 rounded-full animate-bounce [animation-delay:-0.15s]"></div>
                                        <div className="w-1.5 h-1.5 bg-indigo-400 rounded-full animate-bounce"></div>
                                    </div>
                                </div>
                            </div>
                        )}
                        <div ref={messagesEndRef} />
                    </div>

                    {/* Input Area */}
                    <form onSubmit={handleSendMessage} className="p-4 bg-white border-t border-slate-100 flex gap-2">
                        <input 
                            type="text"
                            value={input}
                            onChange={(e) => setInput(e.target.value)}
                            placeholder="Ask about safety standards..."
                            className="flex-1 bg-slate-100 border border-slate-200 rounded-2xl px-5 py-3 text-xs outline-none focus:ring-4 focus:ring-indigo-50 focus:bg-white transition-all font-medium"
                        />
                        <button 
                            type="submit"
                            disabled={!input.trim() || isTyping}
                            className="w-12 h-12 bg-slate-900 text-white rounded-2xl flex items-center justify-center hover:bg-indigo-600 transition-all active:scale-90 disabled:bg-slate-200 shadow-lg"
                        >
                            <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M12 19l9 2-9-18-9 18 9-2zm0 0v-8" /></svg>
                        </button>
                    </form>
                </div>
            )}

            {/* Redesigned Toggle Button */}
            <button 
                onClick={() => setIsOpen(!isOpen)}
                className={`group h-16 w-16 rounded-[1.5rem] shadow-[0_10px_30px_-10px_rgba(0,0,0,0.3)] flex items-center justify-center transition-all duration-500 relative border-t border-white/10
                    ${isOpen ? 'bg-indigo-600 rotate-180 rounded-full' : 'bg-slate-900 hover:bg-black hover:scale-110 active:scale-95'}
                `}
            >
                {isOpen ? (
                    <svg className="w-7 h-7 text-white" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M6 18L18 6M6 6l12 12" /></svg>
                ) : (
                    <div className="relative">
                        <svg className="w-8 h-8 text-white transition-transform group-hover:rotate-12 group-hover:scale-110" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="1.5" d="M8 10h.01M12 10h.01M16 10h.01M9 16H5a2 2 0 01-2-2V6a2 2 0 012-2h14a2 2 0 012 2v8a2 2 0 01-2 2h-5l-5 5v-5z" />
                        </svg>
                        <div className="absolute -top-3 -right-3 h-5 min-w-[20px] bg-indigo-500 text-white text-[8px] font-black flex items-center justify-center rounded-full border-2 border-slate-900 px-1 shadow-lg animate-pulse">
                            AI
                        </div>
                    </div>
                )}

                {/* Subtle Indicator Shadow Pulse */}
                {!isOpen && (
                    <span className="absolute inset-0 rounded-[1.5rem] bg-indigo-500/20 animate-ping pointer-events-none"></span>
                )}
            </button>
        </div>
    );
};

