                                    onChange={(e) => setInput(e.target.value)}
                                    placeholder="Type your message..."
                                    className="flex-1 bg-slate-50 border border-slate-100 rounded-2xl px-5 py-3.5 text-xs outline-none focus:ring-4 focus:ring-indigo-50/50 focus:bg-white transition-all font-medium"
