                                <button 
                                    type="submit"
                                    disabled={!input.trim() || isSending}
                                    className="w-12 h-12 bg-[#0f172a] text-white rounded-2xl flex items-center justify-center hover:bg-black transition-all active:scale-90 disabled:bg-slate-200 shadow-xl"
                                >
                                    {isSending ? (
                                        <div className="w-5 h-5 border-2 border-white/30 border-t-white rounded-full animate-spin"></div>
                                    ) : (
                                        <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24" strokeWidth="2.5"><path d="M12 19l9 2-9-18-9 18 9-2zm0 0v-8" /></svg>
