const CODE_CONTROLLER = `
// 1. CONTROLLER (Main Entry & Routing)

function doPost(e) {
  const lock = LockService.getScriptLock();
  lock.tryLock(30000); 

  try {
    const ss = SpreadsheetApp.getActiveSpreadsheet();
    const body = e.postData ? JSON.parse(e.postData.contents) : {};
    return routeRequest(ss, body);
  } catch (err) {
    return ResponseBuilder.error(err.toString());
  } finally {
    lock.releaseLock();
  }
}

function doGet(e) {
  const ss = SpreadsheetApp.getActiveSpreadsheet();
  SystemHandlers.cleanupOldNotifications(ss);
  return DataHandlers.handleGetRequest(ss);
}

function routeRequest(ss, body) {
  const action = body.action;
  const routes = {
    'login': () => AuthHandlers.handleLogin(ss, body),
    'register_user': () => AuthHandlers.handleRegisterUser(ss, body),
    'get_users': () => AuthHandlers.handleGetUsers(ss),
    'delete_user': () => AuthHandlers.handleDeleteUser(ss, body),
    'update_user': () => AuthHandlers.handleUpdateUser(ss, body),
    'heartbeat': () => AuthHandlers.handleHeartbeat(ss, body),
    'manage_fleet': () => SystemHandlers.handleManageFleet(ss, body),
    'bulk_manage_fleet': () => SystemHandlers.handleBulkManageFleet(ss, body),
    'acknowledge_issue': () => SystemHandlers.handleAcknowledgeIssue(ss, body),
    'request_inspection': () => SystemHandlers.handleRequestInspection(ss, body),
    'get_acknowledgements': () => SystemHandlers.handleGetAcknowledgements(ss),
    'mark_notification_read': () => SystemHandlers.handleMarkNotificationRead(ss, body),
    'update_settings': () => SystemHandlers.handleUpdateSettings(ss, body),
    'broadcast': () => SystemHandlers.handleBroadcast(ss, body),
    'check_subscription': () => SubscriptionHandlers.handleCheckSubscription(ss),
    'extend_subscription': () => SubscriptionHandlers.handleExtendSubscription(ss, body),
    'submit_support_ticket': () => SupportHandlers.handleSubmitSupport(ss, body),
    'get_tickets': () => SupportHandlers.handleGetTickets(ss, body),
    'update_ticket': () => SupportHandlers.handleUpdateTicket(ss, body),
    'initiate_mobile_payment': () => PaymentHandlers.handleMobileMoney(ss, body)
  };

  if (!action || action === 'create' || !routes[action]) {
    return DataHandlers.handleDataSubmission(ss, body);
  }
  return routes[action]();
}`;

const CODE_AUTH = `
const AuthHandlers = {
  handleLogin: function(ss, body) {
    let userSheet = ss.getSheetByName('Users');
    if (!userSheet) return ResponseBuilder.error("No users found.");
    const data = userSheet.getDataRange().getValues();
    const username = body.username.toLowerCase();
    for (let i = 1; i < data.length; i++) {
        if (data[i][0].toLowerCase() === username && data[i][1] === body.password) {
            return ResponseBuilder.success({ user: { username: data[i][0], name: data[i][2], role: data[i][3] } });
        }
    }
    return ResponseBuilder.error("Invalid credentials.");
  },
  handleHeartbeat: function(ss, body) {
    let sheet = ss.getSheetByName('Users');
    const data = sheet.getDataRange().getValues();
    for (let i = 1; i < data.length; i++) {
      if (data[i][0].toLowerCase() === body.username.toLowerCase()) {
        sheet.getRange(i + 1, 9).setValue(new Date().toISOString()); // Last Seen
        sheet.getRange(i + 1, 10).setValue(body.isTyping ? "TRUE" : "FALSE"); // Is Typing
        return ResponseBuilder.success();
      }
    }
    return ResponseBuilder.error("User not found");
  },
  handleRegisterUser: function(ss, body) {
    let sheet = ss.getSheetByName('Users') || ss.insertSheet('Users');
    sheet.appendRow([body.username.toLowerCase(), body.password, body.name, body.role, body.position, new Date().toISOString(), "{}", "TRUE", "", "FALSE"]);
    return ResponseBuilder.success();
  },
  handleGetUsers: function(ss) {
    let sheet = ss.getSheetByName('Users');
    if (!sheet) return ResponseBuilder.success({ users: [] });
    const data = sheet.getDataRange().getValues();
    const users = data.slice(1).map(r => ({ 
      username: r[0], 
      name: r[2], 
      role: r[3], 
      position: r[4], 
      isActive: r[7] === "TRUE",
      lastSeen: r[8],
      isTyping: r[9] === "TRUE"
    }));
    return ResponseBuilder.success({ users });
  },
  handleDeleteUser: function(ss, body) {
    let sheet = ss.getSheetByName('Users');
    const data = sheet.getDataRange().getValues();
    for (let i = 1; i < data.length; i++) {
      if (data[i][0].toLowerCase() === body.username.toLowerCase()) {
        sheet.deleteRow(i + 1);
        return ResponseBuilder.success();
      }
    }
    return ResponseBuilder.error("User not found");
  },
  handleUpdateUser: function(ss, body) {
    let sheet = ss.getSheetByName('Users');
    const data = sheet.getDataRange().getValues();
    for (let i = 1; i < data.length; i++) {
      if (data[i][0].toLowerCase() === (body.originalUsername || body.username).toLowerCase()) {
        if (body.username) sheet.getRange(i + 1, 1).setValue(body.username);
        if (body.password) sheet.getRange(i + 1, 2).setValue(body.password);
        if (body.name) sheet.getRange(i + 1, 3).setValue(body.name);
        if (body.role) sheet.getRange(i + 1, 4).setValue(body.role);
        if (body.position) sheet.getRange(i + 1, 5).setValue(body.position);
        if (body.isActive !== undefined) sheet.getRange(i + 1, 8).setValue(body.isActive ? "TRUE" : "FALSE");
        if (body.preferences) sheet.getRange(i + 1, 7).setValue(JSON.stringify(body.preferences));
        return ResponseBuilder.success();
      }
    }
    return ResponseBuilder.error("User not found");
  }
};`;

const CODE_CORE_OPS = `
// 3. CORE OPERATIONS (Data, Systems, Subscription)

const DataHandlers = {
  handleDataSubmission: function(ss, body) {
    const sheetName = body.sheet;
    const headers = body.headers;
    const rowData = body.row;
    let sheet = ss.getSheetByName(sheetName);
    if (!sheet) {
      sheet = ss.insertSheet(sheetName);
      if (headers && Array.isArray(headers)) {
        sheet.appendRow(headers);
        sheet.getRange(1, 1, 1, headers.length).setFontWeight("bold");
        sheet.setFrozenRows(1);
      }
    }
    const safeRow = rowData.map(r => (r === null || r === undefined) ? "" : String(r));
    sheet.appendRow(safeRow);

    if (body.requestId) {
        const reqSheet = ss.getSheetByName('Inspection_Requests');
        if (reqSheet) {
            const reqData = reqSheet.getDataRange().getValues();
            for (let i = 1; i < reqData.length; i++) {
                if (String(reqData[i][0]) === String(body.requestId)) {
                    reqSheet.getRange(i + 1, 10).setValue('Completed');
                    break;
                }
            }
        }
    }

    if (body.reportData) {
      EmailDispatcher.sendInspectionReport(body.reportData);
    }

    return ResponseBuilder.success({ sheet: sheetName });
  },

  handleGetRequest: function(ss) {
    const sheets = ss.getSheets();
    const data = {};
    sheets.forEach(sheet => {
      const name = sheet.getName();
      if (name === 'Users' || name === 'System_Logs') return;
      const lastRow = sheet.getLastRow();
      if (lastRow === 0) { data[name] = []; return; }

      if (name === 'Validation_Data') {
         if (lastRow > 1) {
            const range = sheet.getRange(2, 1, lastRow - 1, sheet.getLastColumn());
            const values = range.getValues();
            const columns = {};
            const headers = sheet.getRange(1, 1, 1, sheet.getLastColumn()).getValues()[0];
            headers.forEach((h, colIndex) => {
               columns[h] = [...new Set(values.map(row => row[colIndex]).filter(c => c !== ""))]; 
            });
            data[name] = columns;
         } else { data[name] = {}; }
      } else if (name === 'Subscription_Data') {
          const values = sheet.getDataRange().getValues();
          if (values.length > 1) {
            const history = [];
            for (let i = 1; i < values.length; i++) {
                const row = values[i];
                let expiry = row[2];
                if (expiry instanceof Date) expiry = Utilities.formatDate(expiry, ss.getSpreadsheetTimeZone(), "yyyy-MM-dd");
                history.push({ status: row[0], plan: row[1], expiryDate: expiry, processedBy: row[3], timestamp: row[4] });
            }
            data[name] = { current: history[history.length - 1], history: history };
          } else { data[name] = { current: { status: "Expired", plan: "None", expiryDate: "" }, history: [] }; }
      } else {
         const startRow = Math.max(1, lastRow - 150);
         const values = sheet.getRange(startRow, 1, lastRow - startRow + 1, sheet.getLastColumn()).getValues();
         if (startRow > 1) values.unshift(sheet.getRange(1, 1, 1, sheet.getLastColumn()).getValues()[0]);
         data[name] = values;
      }
    });
    return ResponseBuilder.build(data);
  }
};

const PaymentHandlers = {
  handleMobileMoney: function(ss, body) {
    const settingsSheet = ss.getSheetByName('System_Settings');
    const secretKey = settingsSheet ? settingsSheet.getRange(2, 10).getValue() : null; // Col J

    if (!secretKey) return ResponseBuilder.error("Payment system not configured. Secret Key missing.");

    const tx_ref = "TXN-" + Date.now();
    const payload = {
      "amount": body.amount,
      "currency": "ZMW",
      "phone_number": body.phoneNumber,
      "network": body.network, // MTN or AIRTEL
      "email": body.email,
      "tx_ref": tx_ref,
      "order_id": "SUB-" + Date.now(),
      "description": body.description,
      "country": "ZM"
    };

    const options = {
      "method": "post",
      "contentType": "application/json",
      "headers": { "Authorization": "Bearer " + secretKey },
      "payload": JSON.stringify(payload),
      "muteHttpExceptions": true
    };

    try {
      // Flutterwave Zambian Mobile Money Endpoint
      const response = UrlFetchApp.fetch("https://api.flutterwave.com/v3/charges?type=mobile_money_zambia", options);
      const resData = JSON.parse(response.getContentText());

      if (resData.status === "success") {
        return ResponseBuilder.success({ 
           message: "PIN Prompt sent to " + body.phoneNumber, 
           tx_ref: tx_ref,
           flw_ref: resData.data.flw_ref 
        });
      } else {
        return ResponseBuilder.error(resData.message || "Failed to initiate payment prompt.");
      }
    } catch (e) {
      return ResponseBuilder.error("Network error connecting to payment gateway.");
    }
  }
};

const SubscriptionHandlers = {
  handleCheckSubscription: function(ss) {
    let subSheet = ss.getSheetByName('Subscription_Data') || ss.insertSheet('Subscription_Data');
    if (subSheet.getLastRow() < 2) {
        const defaultExpiry = new Date();
        defaultExpiry.setDate(defaultExpiry.getDate() + 30);
        subSheet.appendRow(["Active", "Trial", defaultExpiry.toISOString(), new Date().toISOString()]);
    }
    const lastRow = subSheet.getLastRow();
    const data = subSheet.getRange(lastRow, 1, 1, 4).getValues()[0];
    let status = data[0];
    const expiry = new Date(data[2]);
    const now = new Date();
    if (status === 'Active' && !isNaN(expiry.getTime()) && now > expiry) {
        status = 'Expired';
        subSheet.getRange(lastRow, 1).setValue('Expired');
    }
    return ResponseBuilder.success({ 
        subscription: {
            status: status,
            plan: data[1],
            expiryDate: data[2],
            daysRemaining: Math.ceil((expiry.getTime() - now.getTime()) / (1000 * 60 * 60 * 24))
        }
    });
  },
  handleExtendSubscription: function(ss, body) {
    let subSheet = ss.getSheetByName('Subscription_Data') || ss.insertSheet('Subscription_Data');
    if (subSheet.getLastRow() === 0) {
      subSheet.getRange(1, 1, 1, 5).setValues([["Status", "Plan", "ExpiryDate", "ProcessedBy", "Timestamp"]]);
      subSheet.setFrozenRows(1);
    }
    subSheet.appendRow(["Active", body.plan || "Enterprise", body.expiryDate, body.processedBy || "System", new Date().toISOString()]);
    return ResponseBuilder.success({ message: "Subscription updated" });
  }
};

const SystemHandlers = {
  handleUpdateSettings: function(ss, body) {
    let settingsSheet = ss.getSheetByName('System_Settings') || ss.insertSheet('System_Settings');
    const updateRow = [
      body.companyName || '', 
      body.managerEmail || '', 
      new Date(), 
      body.updatedBy || "Admin", 
      body.companyLogo || '', 
      "", "", 
      body.maintenanceMode ? "TRUE" : "FALSE", 
      body.maintenanceMessage || '',
      body.flutterwaveSecretKey || '' // Column J
    ];
    if (settingsSheet.getLastRow() < 2) {
      if (settingsSheet.getLastRow() === 0) settingsSheet.appendRow(["CompanyName", "ManagerEmail", "UpdatedBy", "Timestamp", "LogoBase64", "MobileApkLink", "WebAppUrl", "MaintenanceMode", "MaintenanceMessage", "FLW_Secret_Key"]);
      settingsSheet.appendRow(updateRow);
    } else {
      settingsSheet.getRange(2, 1, 1, updateRow.length).setValues([updateRow]);
    }
    return ResponseBuilder.success({ message: "Settings updated" });
  },
  cleanupOldNotifications: function(ss) {}
};

const EmailDispatcher = {
  sendInspectionReport: function(data) {
    try {
      const settingsSheet = SpreadsheetApp.getActiveSpreadsheet().getSheetByName('System_Settings');
      let adminEmail = "";
      if (settingsSheet && settingsSheet.getLastRow() > 1) adminEmail = settingsSheet.getRange(2, 3).getValue();
      if (!adminEmail) return;
      const htmlBody = this.buildHtmlReport(data);
      const blob = Utilities.newBlob(htmlBody, "text/html", "Report.html");
      const pdf = blob.getAs("application/pdf").setName("Report_" + data.truckNo + ".pdf");
      MailApp.sendEmail({
        to: adminEmail,
        subject: "Report: " + data.truckNo,
        htmlBody: "PDF attached.",
        attachments: [pdf]
      });
    } catch (e) {}
  },
  buildHtmlReport: function(data) { return "<h1>" + data.title + "</h1>"; }
};
`;

const CODE_LIB = `const ResponseBuilder = {
  success: function(data = {}) { return this.build({ status: "success", ...data }); },
  error: function(message) { return this.build({ status: "error", message: message }); },
  build: function(data) { return ContentService.createTextOutput(JSON.stringify(data)).setMimeType(ContentService.MimeType.JSON); }
};`;

export const BACKEND_FILES: Record<string, string> = {
    '1_Controller.gs': CODE_CONTROLLER,
    '2_Auth.gs': CODE_AUTH,
    '3_Core.gs': CODE_CORE_OPS,
    '5_Utils.gs': CODE_LIB
};

export const BACKEND_SCRIPT_TEMPLATE = Object.values(BACKEND_FILES).join('\n\n');

import React, { useState, useRef, useEffect, useMemo } from 'react';
import { User, ChatMessage } from '../../types';

interface ChatAssistantProps {
    currentUser: User | null;
    appScriptUrl: string;
}

const ChatAssistant: React.FC<ChatAssistantProps> = ({ currentUser, appScriptUrl }) => {
    const [isOpen, setIsOpen] = useState(false);
    const [view, setView] = useState<'list' | 'chat'>('list');
    const [input, setInput] = useState('');
    const [messages, setMessages] = useState<ChatMessage[]>([]);
    const [staff, setStaff] = useState<User[]>([]);
    const [searchTerm, setSearchTerm] = useState('');
    const [isSending, setIsSending] = useState(false);
    const [isLoading, setIsLoading] = useState(false);
    const [lastReadCount, setLastReadCount] = useState<number>(() => {
        const saved = localStorage.getItem('sc_chat_read_count');
        return saved ? parseInt(saved, 10) : 0;
    });

    const messagesEndRef = useRef<HTMLDivElement>(null);
    const lastFetchRef = useRef<number>(0);
    const heartbeatRef = useRef<number | null>(null);

    const scrollToBottom = () => {
        messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
    };

    const unreadCount = useMemo(() => {
        if (messages.length <= lastReadCount) return 0;
        return messages.length - lastReadCount;
    }, [messages.length, lastReadCount]);

    // Heartbeat logic
    const sendHeartbeat = async () => {
        if (!appScriptUrl || !currentUser) return;
        try {
            await fetch(appScriptUrl, {
                method: 'POST',
                body: JSON.stringify({
                    action: 'heartbeat',
                    username: currentUser.username,
                    isTyping: input.trim().length > 0 && view === 'chat'
                }),
                mode: 'no-cors'
            });
        } catch (e) {
            console.debug("Heartbeat missed");
        }
    };

    useEffect(() => {
        if (currentUser) {
            sendHeartbeat();
            heartbeatRef.current = window.setInterval(sendHeartbeat, 20000);
        }
        return () => {
            if (heartbeatRef.current) window.clearInterval(heartbeatRef.current);
        };
    }, [currentUser, input, view]);

    // Update read count
    useEffect(() => {
        if (isOpen && view === 'chat') {
            const count = messages.length;
            setLastReadCount(count);
            localStorage.setItem('sc_chat_read_count', count.toString());
        }
    }, [isOpen, view, messages.length]);

    const fetchData = async (showLoading = false) => {
        if (!appScriptUrl || !currentUser) return;

        const now = Date.now();
        if (now - lastFetchRef.current < 2000) return; 
        lastFetchRef.current = now;

        if (showLoading) setIsLoading(true);
        try {
            const response = await fetch(`${appScriptUrl}?t=${now}`);
            const json = await response.json();

            const chatData = json['Messages'];
            if (chatData && Array.isArray(chatData) && chatData.length > 1) {
                const mappedMessages: ChatMessage[] = chatData.slice(1).map((row: any[]) => ({
                    timestamp: row[0],
                    user: row[1],
                    message: row[2],
                    role: row[3]
                }));
                setMessages(mappedMessages);
            }

            const userResponse = await fetch(appScriptUrl, {
                method: 'POST',
                body: JSON.stringify({ action: 'get_users' })
            });
            const userData = await userResponse.json();
            if (userData.status === 'success' && Array.isArray(userData.users)) {
                setStaff(userData.users.filter(u => u.username !== currentUser.username));
            }
        } catch (error) {
            console.error("Chat sync failed", error);
        } finally {
            setIsLoading(false);
        }
    };

    useEffect(() => {
        fetchData(true);
        const interval = window.setInterval(() => fetchData(false), 8000);
        return () => window.clearInterval(interval);
    }, [appScriptUrl, currentUser?.username]);

    useEffect(() => {
        if (isOpen && view === 'chat') scrollToBottom();
    }, [messages, isOpen, view, staff]);

    const handleSendMessage = async (isBroadcast = false) => {
        if (!input.trim() || isSending || !currentUser) return;

        const text = isBroadcast ? `[BROADCAST]: ${input.trim()}` : input.trim();
        setInput('');
        setIsSending(true);

        const payload = {
            action: 'create',
            sheet: 'Messages',
            headers: ['timestamp', 'user', 'message', 'role'],
            row: [new Date().toISOString(), currentUser.name, text, currentUser.role]
        };

        try {
            await fetch(appScriptUrl, {
                method: 'POST',
                body: JSON.stringify(payload),
                mode: 'no-cors'
            });

            const optimisticMsg: ChatMessage = {
                timestamp: new Date().toISOString(),
                user: currentUser.name,
                message: text,
                role: currentUser.role
            };
            setMessages(prev => [...prev, optimisticMsg]);
            if (view === 'list') setView('chat');
        } catch (error) {
            console.error("Message send failed", error);
        } finally {
            setIsSending(false);
        }
    };

    const filteredStaff = staff.filter(s => 
        s.name?.toLowerCase().includes(searchTerm.toLowerCase()) || 
        s.username?.toLowerCase().includes(searchTerm.toLowerCase())
    );

    const lastMessageMap = useMemo(() => {
        const map: Record<string, ChatMessage> = {};
        messages.forEach(msg => {
            map[msg.user] = msg;
        });
        return map;
    }, [messages]);

    const isUserOnline = (member: any) => {
        if (!member.lastSeen) return false;
        const diff = Date.now() - new Date(member.lastSeen).getTime();
        return diff < 45000; // Online if seen in last 45 seconds
    };

    const typingUsers = useMemo(() => {
        return staff.filter(s => s.isTyping && isUserOnline(s)).map(s => s.name);
    }, [staff]);

    const MessageStatus = ({ timestamp, isMe }: { timestamp: string, isMe: boolean }) => {
        if (!isMe) return null;
        const diff = Date.now() - new Date(timestamp).getTime();
        const isRead = diff > 6000;
        const isDelivered = diff > 2500;

        return (
            <div className="flex items-center ml-1 shrink-0">
                {isRead ? (
                    <svg className="w-3.5 h-3.5 text-indigo-400" fill="currentColor" viewBox="0 0 24 24"><path d="M0.41 13.41L6 19L7.41 17.58L1.83 12M22.24 5.58L11.66 16.17L7.5 12L6.07 13.41L11.66 19L23.66 7M18 7L16.59 5.58L10.24 11.93L11.66 13.34L18 7Z"/></svg>
                ) : isDelivered ? (
                    <svg className="w-3.5 h-3.5 text-slate-300" fill="currentColor" viewBox="0 0 24 24"><path d="M0.41 13.41L6 19L7.41 17.58L1.83 12M22.24 5.58L11.66 16.17L7.5 12L6.07 13.41L11.66 19L23.66 7M18 7L16.59 5.58L10.24 11.93L11.66 13.34L18 7Z"/></svg>
                ) : (
                    <svg className="w-3.5 h-3.5 text-slate-300" fill="currentColor" viewBox="0 0 24 24"><path d="M21,7L9,19L3.5,13.5L4.91,12.09L9,16.17L19.59,5.59L21,7Z"/></svg>
                )}
            </div>
        );
    };

    return (
        <div className="fixed bottom-6 right-6 z-[110] no-print flex flex-col items-end font-sans">
            {/* Reduced Dimensions Chat Window */}
            {isOpen && (
                <div className="mb-4 w-[330px] sm:w-[350px] h-[440px] bg-white rounded-[2rem] shadow-[0_20px_60px_-15px_rgba(0,0,0,0.3)] border border-slate-200 flex flex-col overflow-hidden animate-fadeIn origin-bottom-right">

                    {/* Header */}
                    <div className="bg-[#0f172a] p-4 flex justify-between items-center shrink-0">
                        <div className="flex items-center gap-3">
                            <div className="w-9 h-9 bg-[#4f46e5] rounded-xl flex items-center justify-center text-white shadow-lg">
                                <svg className="w-5 h-5" fill="currentColor" viewBox="0 0 24 24"><path d="M20 2H4c-1.1 0-2 .9-2 2v18l4-4h14c1.1 0 2-.9 2-2V4c0-1.1-.9-2-2-2z" /></svg>
                            </div>
                            <div>
                                <h3 className="text-[11px] font-bold text-white tracking-tight leading-none uppercase">Team Comms</h3>
                                <div className="flex items-center gap-1 mt-1">
                                    <span className="w-1 h-1 bg-emerald-500 rounded-full animate-pulse"></span>
                                    <span className="text-[7px] text-slate-400 font-bold uppercase tracking-widest">Active Fleet</span>
                                </div>
                            </div>
                        </div>
                        <div className="flex items-center gap-2">
                            <button onClick={() => { setView('chat'); setInput(''); }} className="bg-[#4f46e5] hover:bg-[#4338ca] text-white px-2.5 py-1.5 rounded-lg text-[8px] font-black uppercase tracking-wider flex items-center gap-1 transition-all">
                                <svg className="w-2.5 h-2.5" fill="none" stroke="currentColor" viewBox="0 0 24 24" strokeWidth="3"><path d="M11 5.882V19.24a1.76 1.76 0 01-3.417.592l-2.147-6.15M18 13a3 3 0 100-6M5.436 13.683A4.001 4.001 0 017 6h1.832c4.1 0 7.625-1.234 9.168-3v14c-1.543-1.766-5.067-3-9.168-3H7a3.988 3.988 0 01-1.564-.317z" /></svg>
                                Broadcast
                            </button>
                            <button onClick={() => setIsOpen(false)} className="p-1 text-slate-400 hover:text-white transition-colors">
                                <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24" strokeWidth="3"><path d="M6 18L18 6M6 6l12 12" /></svg>
                            </button>
                        </div>
                    </div>

                    {view === 'list' ? (
                        <>
                            {/* Search */}
                            <div className="px-4 py-2.5 bg-white border-b border-slate-50 shrink-0">
                                <div className="relative">
                                    <svg className="absolute left-3 top-1/2 -translate-y-1/2 w-3.5 h-3.5 text-slate-300" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" strokeWidth="2.5" /></svg>
                                    <input 
                                        type="text" 
                                        placeholder="Find personnel..." 
                                        className="w-full pl-9 pr-4 py-2 bg-slate-50 border border-slate-100 rounded-xl text-[10px] font-medium outline-none focus:ring-2 focus:ring-indigo-50/50 transition-all placeholder:text-slate-400"
                                        value={searchTerm}
                                        onChange={(e) => setSearchTerm(e.target.value)}
                                    />
                                </div>
                            </div>

                            {/* List */}
                            <div className="flex-1 overflow-y-auto scrollbar-hide">
                                <div className="divide-y divide-slate-50">
                                    {filteredStaff.length === 0 ? (
                                        <div className="py-16 text-center text-slate-300 italic text-[9px] uppercase tracking-widest font-bold">Registry Empty</div>
                                    ) : (
                                        filteredStaff.map((member, i) => {
                                            const lastMsg = lastMessageMap[member.name];
                                            const online = isUserOnline(member);
                                            return (
                                                <button key={i} onClick={() => setView('chat')} className="w-full px-4 py-3 hover:bg-slate-50 transition-all flex items-center gap-3 group">
                                                    <div className="relative shrink-0">
                                                        <div className="w-9 h-9 rounded-xl bg-slate-100 border border-slate-200 flex items-center justify-center text-slate-400 group-hover:bg-indigo-50 group-hover:text-indigo-600 transition-colors">
                                                            <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M16 7a4 4 0 11-8 0 4 4 0 018 0zM12 14a7 7 0 00-7 7h14a7 7 0 00-7-7z" strokeWidth="2" /></svg>
                                                        </div>
                                                        <span className={`absolute -bottom-0.5 -right-0.5 w-2.5 h-2.5 border-2 border-white rounded-full ${online ? 'bg-emerald-500 shadow-[0_0_5px_rgba(16,185,129,0.5)]' : 'bg-slate-300'}`}></span>
                                                    </div>
                                                    <div className="flex-1 text-left min-w-0">
                                                        <div className="flex justify-between items-center mb-0.5">
                                                            <h4 className="text-[10px] font-black text-slate-800 uppercase tracking-tight truncate">{member.name}</h4>
                                                            {lastMsg && <span className="text-[7px] text-slate-300 font-bold">{new Date(lastMsg.timestamp).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}</span>}
                                                        </div>
                                                        <p className="text-[9px] text-slate-400 font-medium truncate leading-tight">
                                                            {member.isTyping && online ? <span className="text-indigo-500 font-bold animate-pulse italic">Is responding...</span> : lastMsg ? lastMsg.message : <span className="italic opacity-50">New connection...</span>}
                                                        </p>
                                                    </div>
                                                </button>
                                            );
                                        })
                                    )}
                                </div>
                            </div>
                        </>
                    ) : (
                        <>
                            {/* Chat Header */}
                            <div className="p-3 bg-slate-50 border-b border-slate-100 flex items-center justify-between shrink-0">
                                <div className="flex items-center gap-2">
                                    <button onClick={() => setView('list')} className="p-1.5 hover:bg-white rounded-lg text-slate-400 transition-all">
                                        <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24" strokeWidth="3"><path d="M15 19l-7-7 7-7" /></svg>
                                    </button>
                                    <div>
                                        <h4 className="text-[10px] font-black text-slate-800 uppercase tracking-widest leading-none">Internal Board</h4>
                                        <p className="text-[7px] text-emerald-500 font-bold uppercase tracking-widest mt-1 flex items-center gap-1">
                                            <span className="w-1 h-1 bg-emerald-500 rounded-full"></span> {typingUsers.length > 0 ? `${typingUsers.join(', ')} typing...` : 'End-to-End Secure'}
                                        </p>
                                    </div>
                                </div>
                            </div>

                            {/* Messages */}
                            <div className="flex-1 overflow-y-auto p-4 space-y-4 bg-slate-50/30 scrollbar-hide">
                                {messages.map((msg, idx) => {
                                    const isMe = msg.user === currentUser?.name;
                                    const isBroadcast = msg.message.startsWith('[BROADCAST]:');
                                    return (
                                        <div key={idx} className={`flex flex-col ${isMe ? 'items-end' : 'items-start'}`}>
                                            {!isMe && (
                                                <span className="text-[7px] font-black text-slate-400 uppercase tracking-widest mb-1 ml-1 flex items-center gap-1.5">
                                                    {msg.user}
                                                    {isBroadcast && <span className="bg-indigo-50 text-indigo-500 px-1 rounded-[4px] text-[6px]">SYSTEM</span>}
                                                </span>
                                            )}
                                            <div className="flex items-end gap-1 group">
                                                {isMe && <MessageStatus timestamp={msg.timestamp} isMe={true} />}
                                                <div className={`max-w-[210px] p-3 text-[10.5px] leading-relaxed shadow-sm border ${
                                                    isMe 
                                                    ? 'bg-[#0f172a] text-white rounded-2xl rounded-tr-none border-[#0f172a]' 
                                                    : isBroadcast
                                                        ? 'bg-indigo-50 text-indigo-900 border-indigo-100 rounded-2xl rounded-tl-none'
                                                        : 'bg-white text-slate-700 border-slate-200 rounded-2xl rounded-tl-none'
                                                }`}>
                                                    {isBroadcast ? msg.message.replace('[BROADCAST]:', '').trim() : msg.message}
                                                </div>
                                            </div>
                                            <span className="text-[6px] text-slate-300 font-bold uppercase mt-1 px-1">
                                                {new Date(msg.timestamp).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                                            </span>
                                        </div>
                                    );
                                })}
                                <div ref={messagesEndRef} />
                            </div>

                            {/* Input */}
                            <form onSubmit={(e) => { e.preventDefault(); handleSendMessage(); }} className="p-3 bg-white border-t border-slate-100 flex gap-2 shrink-0">
                                <input 
                                    type="text"
                                    value={input}
                                    onChange={(e) => setInput(e.target.value)}
                                    placeholder="Type your message..."
                                    className="flex-1 bg-slate-50 border border-slate-100 rounded-xl px-4 py-2.5 text-[11px] outline-none focus:ring-2 focus:ring-indigo-50/50 focus:bg-white transition-all font-medium"
                                />
                                <button type="submit" disabled={!input.trim() || isSending} className="w-10 h-10 bg-[#0f172a] text-white rounded-xl flex items-center justify-center hover:bg-black transition-all active:scale-90 disabled:bg-slate-200">
                                    {isSending ? <div className="w-4 h-4 border-2 border-white/30 border-t-white rounded-full animate-spin"></div> : <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24" strokeWidth="3"><path d="M12 19l9 2-9-18-9 18 9-2zm0 0v-8" /></svg>}
                                </button>
                            </form>
                        </>
                    )}
                </div>
            )}

            {/* Toggle */}
            <button 
                onClick={() => setIsOpen(!isOpen)}
                className={`group h-16 w-16 rounded-[1.8rem] shadow-[0_15px_40px_-10px_rgba(0,0,0,0.4)] flex items-center justify-center transition-all duration-500 relative border-t border-white/10
                    ${isOpen ? 'bg-[#4f46e5] rotate-180 rounded-full' : 'bg-[#0f172a] hover:bg-black hover:scale-110 active:scale-95'}
                `}
            >
                {isOpen ? (
                    <svg className="w-7 h-7 text-white" fill="none" stroke="currentColor" viewBox="0 0 24 24" strokeWidth="3"><path d="M6 18L18 6M6 6l12 12" /></svg>
                ) : (
                    <div className="relative">
                        <svg className="w-8 h-8 text-white transition-transform group-hover:rotate-12 group-hover:scale-110" fill="currentColor" viewBox="0 0 24 24">
                            <path d="M20 2H4c-1.1 0-2 .9-2 2v18l4-4h14c1.1 0 2-.9 2-2V4c0-1.1-.9-2-2-2z" />
                        </svg>
                        {unreadCount > 0 && (
                            <div className="absolute -top-3 -right-3 h-6 min-w-[24px] bg-[#ef4444] text-white text-[9px] font-black flex items-center justify-center rounded-full border-[3px] border-[#0f172a] px-1.5 shadow-xl animate-bounce">
                                {unreadCount > 99 ? '99+' : unreadCount}
                            </div>
                        )}
                    </div>
                )}
            </button>
        </div>
    );
};

