                )}
            </button>
        </div>
    );
};

export default ChatAssistant;

import React, { useState, useRef, useEffect, useMemo } from 'react';
import { User, ChatMessage } from '../../types';

interface ChatAssistantProps {
    currentUser: User | null;
    appScriptUrl: string;
}

const ChatAssistant: React.FC<ChatAssistantProps> = ({ currentUser, appScriptUrl }) => {
    const [isOpen, setIsOpen] = useState(false);
    const [view, setView] = useState<'list' | 'chat'>('list');
    const [input, setInput] = useState('');

    // Smart Caching: Initialize state from LocalStorage for instant UI response
    const [messages, setMessages] = useState<ChatMessage[]>(() => {
        const cached = localStorage.getItem('sc_chat_cache_messages');
        return cached ? JSON.parse(cached) : [];
    });

    const [staff, setStaff] = useState<User[]>(() => {
        const cached = localStorage.getItem('sc_chat_cache_staff');
        return cached ? JSON.parse(cached) : [];
    });

    const [searchTerm, setSearchTerm] = useState('');
    const [isSending, setIsSending] = useState(false);
    const [isLoading, setIsLoading] = useState(false);
    const [lastReadCount, setLastReadCount] = useState<number>(() => {
        const saved = localStorage.getItem('sc_chat_read_count');
        return saved ? parseInt(saved, 10) : 0;
    });

    const messagesEndRef = useRef<HTMLDivElement>(null);
    const lastFetchRef = useRef<number>(0);
    const heartbeatRef = useRef<number | null>(null);

    const scrollToBottom = () => {
        messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
    };

    const unreadCount = useMemo(() => {
        if (messages.length <= lastReadCount) return 0;
        return messages.length - lastReadCount;
    }, [messages.length, lastReadCount]);

    // Heartbeat logic
    const sendHeartbeat = async () => {
        if (!appScriptUrl || !currentUser) return;
        try {
            await fetch(appScriptUrl, {
                method: 'POST',
                body: JSON.stringify({
                    action: 'heartbeat',
                    username: currentUser.username,
                    isTyping: input.trim().length > 0 && view === 'chat'
                }),
                mode: 'no-cors'
            });
        } catch (e) {
            console.debug("Heartbeat missed");
        }
    };

    useEffect(() => {
        if (currentUser) {
            sendHeartbeat();
            heartbeatRef.current = window.setInterval(sendHeartbeat, 20000);
        }
        return () => {
            if (heartbeatRef.current) window.clearInterval(heartbeatRef.current);
        };
    }, [currentUser, input, view]);

    // Update read count
    useEffect(() => {
        if (isOpen && view === 'chat') {
            const count = messages.length;
            setLastReadCount(count);
            localStorage.setItem('sc_chat_read_count', count.toString());
        }
    }, [isOpen, view, messages.length]);

    const fetchData = async (showLoading = false) => {
        if (!appScriptUrl || !currentUser) return;

        const now = Date.now();
        if (now - lastFetchRef.current < 2000) return; 
        lastFetchRef.current = now;

        if (showLoading && staff.length === 0) setIsLoading(true);
        try {
            // Parallel execution to speed up loading
            const [msgResponse, userResponse] = await Promise.all([
                fetch(`${appScriptUrl}?t=${now}`),
                fetch(appScriptUrl, {
                    method: 'POST',
                    body: JSON.stringify({ action: 'get_users' })
                })
            ]);

            const json = await msgResponse.json();
            const userData = await userResponse.json();

            // 1. Process Messages
            const chatData = json['Messages'];
            if (chatData && Array.isArray(chatData) && chatData.length > 1) {
                const mappedMessages: ChatMessage[] = chatData.slice(1).map((row: any[]) => ({
                    timestamp: row[0],
                    user: row[1],
                    message: row[2],
                    role: row[3]
                }));
                setMessages(mappedMessages);
                localStorage.setItem('sc_chat_cache_messages', JSON.stringify(mappedMessages));
            }

            // 2. Process Staff
            if (userData.status === 'success' && Array.isArray(userData.users)) {
                const filteredStaff = userData.users.filter((u: User) => u.username !== currentUser.username);
                setStaff(filteredStaff);
                localStorage.setItem('sc_chat_cache_staff', JSON.stringify(filteredStaff));
            }
        } catch (error) {
            console.error("Chat sync failed", error);
        } finally {
            setIsLoading(false);
        }
    };

    useEffect(() => {
        fetchData(true);
        const interval = window.setInterval(() => fetchData(false), 8000);
        return () => window.clearInterval(interval);
    }, [appScriptUrl, currentUser?.username]);

    useEffect(() => {
        if (isOpen && view === 'chat') scrollToBottom();
    }, [messages, isOpen, view, staff]);

    const handleSendMessage = async (isBroadcast = false) => {
        if (!input.trim() || isSending || !currentUser) return;

        const text = isBroadcast ? `[BROADCAST]: ${input.trim()}` : input.trim();
        setInput('');
        setIsSending(true);

        const payload = {
            action: 'create',
            sheet: 'Messages',
            headers: ['timestamp', 'user', 'message', 'role'],
            row: [new Date().toISOString(), currentUser.name, text, currentUser.role]
        };

        try {
            await fetch(appScriptUrl, {
                method: 'POST',
                body: JSON.stringify(payload),
                mode: 'no-cors'
            });

            const optimisticMsg: ChatMessage = {
                timestamp: new Date().toISOString(),
                user: currentUser.name,
                message: text,
                role: currentUser.role
            };
            const updatedMsgs = [...messages, optimisticMsg];
            setMessages(updatedMsgs);
            localStorage.setItem('sc_chat_cache_messages', JSON.stringify(updatedMsgs));
            if (view === 'list') setView('chat');
        } catch (error) {
            console.error("Message send failed", error);
        } finally {
            setIsSending(false);
        }
    };

    const filteredStaff = staff.filter(s => 
        s.name?.toLowerCase().includes(searchTerm.toLowerCase()) || 
        s.username?.toLowerCase().includes(searchTerm.toLowerCase())
    );

    const lastMessageMap = useMemo(() => {
        const map: Record<string, ChatMessage> = {};
        messages.forEach(msg => {
            map[msg.user] = msg;
        });
        return map;
    }, [messages]);

    const isUserOnline = (member: User) => {
        if (!member.lastSeen) return false;
        const diff = Date.now() - new Date(member.lastSeen).getTime();
        return diff < 45000; // Online if seen in last 45 seconds
    };

    const typingUsers = useMemo(() => {
        return staff.filter(s => s.isTyping && isUserOnline(s)).map(s => s.name);
    }, [staff]);

    const MessageStatus = ({ timestamp, isMe }: { timestamp: string, isMe: boolean }) => {
        if (!isMe) return null;
        const diff = Date.now() - new Date(timestamp).getTime();
        const isRead = diff > 6000;
        const isDelivered = diff > 2500;

        return (
            <div className="flex items-center ml-1 shrink-0">
                {isRead ? (
                    <svg className="w-3.5 h-3.5 text-indigo-400" fill="currentColor" viewBox="0 0 24 24"><path d="M0.41 13.41L6 19L7.41 17.58L1.83 12M22.24 5.58L11.66 16.17L7.5 12L6.07 13.41L11.66 19L23.66 7M18 7L16.59 5.58L10.24 11.93L11.66 13.34L18 7Z"/></svg>
                ) : isDelivered ? (
                    <svg className="w-3.5 h-3.5 text-slate-300" fill="currentColor" viewBox="0 0 24 24"><path d="M0.41 13.41L6 19L7.41 17.58L1.83 12M22.24 5.58L11.66 16.17L7.5 12L6.07 13.41L11.66 19L23.66 7M18 7L16.59 5.58L10.24 11.93L11.66 13.34L18 7Z"/></svg>
                ) : (
                    <svg className="w-3.5 h-3.5 text-slate-300" fill="currentColor" viewBox="0 0 24 24"><path d="M21,7L9,19L3.5,13.5L4.91,12.09L9,16.17L19.59,5.59L21,7Z"/></svg>
                )}
            </div>
        );
    };

    return (
        <div className="fixed bottom-6 right-6 z-[110] no-print flex flex-col items-end font-sans">
            {/* Reduced Dimensions Chat Window */}
            {isOpen && (
                <div className="mb-4 w-[330px] sm:w-[350px] h-[440px] bg-white rounded-[2rem] shadow-[0_20px_60px_-15px_rgba(0,0,0,0.3)] border border-slate-200 flex flex-col overflow-hidden animate-fadeIn origin-bottom-right">

                    {/* Header */}
                    <div className="bg-[#0f172a] p-4 flex justify-between items-center shrink-0">
                        <div className="flex items-center gap-3">
                            <div className="w-9 h-9 bg-[#4f46e5] rounded-xl flex items-center justify-center text-white shadow-lg">
                                <svg className="w-5 h-5" fill="currentColor" viewBox="0 0 24 24"><path d="M20 2H4c-1.1 0-2 .9-2 2v18l4-4h14c1.1 0 2-.9 2-2V4c0-1.1-.9-2-2-2z" /></svg>
                            </div>
                            <div>
                                <h3 className="text-[11px] font-bold text-white tracking-tight leading-none uppercase">Team Comms</h3>
                            </div>
                        </div>
                        <div className="flex items-center gap-2">
                            <button onClick={() => { setView('chat'); setInput(''); }} className="bg-[#4f46e5] hover:bg-[#4338ca] text-white px-2.5 py-1.5 rounded-lg text-[8px] font-black uppercase tracking-wider flex items-center gap-1 transition-all">
                                <svg className="w-2.5 h-2.5" fill="none" stroke="currentColor" viewBox="0 0 24 24" strokeWidth="3"><path d="M11 5.882V19.24a1.76 1.76 0 01-3.417.592l-2.147-6.15M18 13a3 3 0 100-6M5.436 13.683A4.001 4.001 0 017 6h1.832c4.1 0 7.625-1.234 9.168-3v14c-1.543-1.766-5.067-3-9.168-3H7a3.988 3.988 0 01-1.564-.317z" /></svg>
                                Broadcast
                            </button>
                            <button onClick={() => setIsOpen(false)} className="p-1 text-slate-400 hover:text-white transition-colors">
                                <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24" strokeWidth="3"><path d="M6 18L18 6M6 6l12 12" /></svg>
                            </button>
                        </div>
                    </div>

                    {view === 'list' ? (
                        <>
                            {/* Search */}
                            <div className="px-4 py-2.5 bg-white border-b border-slate-50 shrink-0">
                                <div className="relative">
                                    <svg className="absolute left-3 top-1/2 -translate-y-1/2 w-3.5 h-3.5 text-slate-300" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" strokeWidth="2.5" /></svg>
                                    <input 
